import { db } from "./db";

const DISCORD_WEBHOOK_URL = process.env.DISCORD_LOG_WEBHOOK_URL || "";

interface LogEntry {
  event: string;
  user?: string;
  email?: string;
  ip: string;
  country?: string | null;
  device?: string;
  hwid?: string;
  key?: string;
  scriptName?: string;
  reason?: string;
  success: boolean;
  timestamp: string;
}

export async function sendDiscordLog(entry: LogEntry) {
  if (!DISCORD_WEBHOOK_URL) return;

  try {
    const color = entry.success ? 0x00ff00 : 0xff0000;
    const fields = [
      { name: "Event", value: entry.event, inline: true },
      { name: "Status", value: entry.success ? "✅ Success" : "❌ Failed", inline: true },
      { name: "IP", value: entry.ip || "unknown", inline: true },
    ];

    if (entry.user) fields.push({ name: "User", value: entry.user, inline: true });
    if (entry.email) fields.push({ name: "Email", value: entry.email, inline: true });
    if (entry.country) fields.push({ name: "Country", value: entry.country, inline: true });
    if (entry.device) fields.push({ name: "Device", value: entry.device, inline: true });
    if (entry.hwid) fields.push({ name: "HWID", value: `\`${entry.hwid.slice(0, 16)}...\``, inline: true });
    if (entry.key) fields.push({ name: "License Key", value: `\`${entry.key}\``, inline: true });
    if (entry.scriptName) fields.push({ name: "Script", value: entry.scriptName, inline: true });
    if (entry.reason) fields.push({ name: "Reason", value: entry.reason, inline: false });

    const payload = {
      embeds: [{
        title: `🔐 ${entry.event}`,
        color,
        fields,
        footer: { text: `Script Shield Security • ${entry.timestamp}` },
        timestamp: entry.timestamp,
      }],
    };

    await fetch(DISCORD_WEBHOOK_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
  } catch (error) {
    // Silent fail — logging should never break the app
    console.error("Discord log failed:", error);
  }
}

// Helper: get recent auth logs for a Discord bot to fetch
export async function getRecentAuthLogs(limit = 50) {
  const [logins, scriptAuths, activations] = await Promise.all([
    db.loginAttempt.findMany({
      take: limit,
      orderBy: { createdAt: "desc" },
      include: { user: { select: { username: true, email: true } } },
    }),
    db.scriptAccessLog.findMany({
      take: limit,
      orderBy: { createdAt: "desc" },
      include: { script: { select: { name: true } } },
    }),
    db.activation.findMany({
      take: limit,
      orderBy: { createdAt: "desc" },
      include: {
        license: { select: { keyHash: true, type: true, status: true } },
      },
    }),
  ]);

  return {
    logins: logins.map(l => ({
      type: "login",
      username: l.user?.username || l.email,
      email: l.email,
      ip: l.ip,
      device: l.deviceName,
      userAgent: l.userAgent,
      success: l.success,
      reason: l.reason,
      timestamp: l.createdAt.toISOString(),
    })),
    scriptAuths: scriptAuths.map(s => ({
      type: "script_auth",
      scriptName: s.script?.name,
      ip: s.ip,
      country: s.country,
      success: s.success,
      reason: s.reason,
      timestamp: s.createdAt.toISOString(),
    })),
    activations: activations.map(a => ({
      type: "activation",
      licenseType: a.license?.type,
      licenseStatus: a.license?.status,
      ip: a.ip,
      country: a.country,
      device: a.deviceInfo,
      hwid: a.fingerprintHash,
      success: a.success,
      reason: a.failureReason,
      timestamp: a.createdAt.toISOString(),
    })),
  };
}

// Helper: blacklist an IP via API
export async function blacklistIp(ip: string, reason: string) {
  if (!ip || ip === "unknown") return { success: false, error: "Invalid IP" };

  await db.ipReputation.upsert({
    where: { ip },
    create: { ip, score: 0, blocked: true, suspiciousLoginCount: 999 },
    update: { score: 0, blocked: true, suspiciousLoginCount: { increment: 1 } },
  });

  // Log the blacklist
  await sendDiscordLog({
    event: "IP_BLACKLISTED",
    ip,
    reason,
    success: true,
    timestamp: new Date().toISOString(),
  });

  return { success: true, message: `IP ${ip} has been blacklisted` };
}

// Helper: unblock an IP
export async function unblockIp(ip: string) {
  if (!ip || ip === "unknown") return { success: false, error: "Invalid IP" };

  await db.ipReputation.update({
    where: { ip },
    data: { blocked: false, score: 80 },
  }).catch(() => {});

  return { success: true, message: `IP ${ip} has been unblocked` };
}

