export async function PUT(
  req: Request,
  { params }: { params: Promise<{ id: string }> },
) {
  const user = await getAuthenticatedUser(req);
  if (!user)
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const { id } = await params;
  const script = await db.script.findUnique({ where: { id } });
  if (!script)
    return NextResponse.json({ error: "Script not found" }, { status: 404 });
  if (!(await canManage(user, script)))
    return NextResponse.json(
      { error: "Access denied. Contact FireLab support." },
      { status: 403 },
    );

  try {
    const body = scriptSchema.safeParse(await getJson(req));
    if (!body.success)
      return NextResponse.json(
        { error: "Invalid script payload", details: body.error.flatten() },
        { status: 400 },
      );

    const data = body.data;
    const storedContent = data.content
      ? data.obfuscate
        ? obfuscateLuaToLoadString(data.content)
        : data.content
      : undefined;
    const updated = await db.script.update({
      where: { id },
      data: {
        name: data.name,
        description: data.description,
        version: data.version,
        contentEncrypted: storedContent
          ? encryptObject({ key: storedContent })
          : undefined,
        contentHash: storedContent ? hashString(storedContent) : undefined,
        visibility: data.content
          ? data.obfuscate
            ? "OBFUSCATED"
            : data.visibility
          : data.visibility,
        status: data.status,
        category: data.category,
        iconUrl: data.iconUrl,
        getKeyLink: data.getKeyLink,
        keyMode: data.keyMode,
        channel: data.channel,
        protectionProfileId: data.protectionProfileId,
        teamId: data.teamId,
      },
    });

    await createAuditLog(
      user.id,
      "SCRIPT_UPDATE",
      {
        scriptId: id,
        scriptName: updated.name,
        obfuscated: Boolean(data.obfuscate),
      },
      undefined,
      req.headers.get("user-agent") || undefined,
      "Script",
      id,
    );
    return NextResponse.json({
      message: "Script protected successfully",
      script: sanitizeScript(updated),
    });
  } catch (error) {
    console.error("PUT Script Error:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 },
    );
  }
}

export async function DELETE(
  req: Request,
  { params }: { params: Promise<{ id: string }> },
) {
  const user = await getAuthenticatedUser(req);
  if (!user)
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const { id } = await params;
  const script = await db.script.findUnique({ where: { id } });
  if (!script)
